import {z} from 'zod';
import {describe,it} from 'vitest';
import fc from 'fast-check';
const Date2=z.string().regex(/^\d{4}-\d{2}-\d{2}$/).transform(s=>new Date(s)).pipe(z.date());
// reverse: Date back to string
function serialize(d:Date){return d.toISOString().slice(0,10);}

describe('Date2 schema round-trip',()=>{
  it('stable after parse-serialize-parse',()=>{
    fc.assert(fc.property(fc.date({min:new Date('2000-01-01'),max:new Date('2030-12-31')}),(d)=>{
      const first=Date2.parse(d.toISOString().slice(0,10));
      const second=Date2.parse(serialize(first));
      return first.getTime()===second.getTime();
    }),{numRuns:300});
  });
});

