import {useState,useEffect} from 'react';
export function AutosaveForm({onSave}:{onSave:(v:string)=>Promise<void>}){
  const [v,setV]=useState('');
  const [dirty,setDirty]=useState(false);
  const [saving,setSaving]=useState(false);
  useEffect(()=>{
    if(!dirty)return;
    const t=setTimeout(async()=>{setSaving(true);await onSave(v);setSaving(false);setDirty(false);},500);
    return ()=>clearTimeout(t);
  },[v,dirty,onSave]);
  return (
    <div>
      <input value={v} onChange={(e)=>{setV(e.target.value);setDirty(true);}}/>
      <span role="status">{saving?'Saving…':dirty?'Modified':'Saved'}</span>
    </div>
  );
}

