import crypto from 'node:crypto';
export function verifyAny(payload:Buffer,sig:string,secrets:string[]):boolean{
  for(const s of secrets){
    const expected=crypto.createHmac('sha256',s).update(payload).digest('hex');
    if(sig.length===expected.length&&crypto.timingSafeEqual(Buffer.from(sig,'hex'),Buffer.from(expected,'hex')))return true;
  }
  return false;
}

import {describe,it,expect} from 'vitest';
import {verifyAny} from './verify';

describe('verifyAny',()=>{
  it('accepts signature from any active secret',()=>{
    const payload=Buffer.from('hello');
    const sig=crypto.createHmac('sha256','OLD').update(payload).digest('hex');
    expect(verifyAny(payload,sig,['NEW','OLD'])).toBe(true);
  });
  it('rejects when neither matches',()=>{
    const payload=Buffer.from('hello');
    const sig=crypto.createHmac('sha256','RETIRED').update(payload).digest('hex');
    expect(verifyAny(payload,sig,['NEW','OLD'])).toBe(false);
  });
});

export class Queue<T>{
  private items:T[]=[];
  enqueue(v:T){this.items.push(v);}
  dequeue():T|undefined{return this.items.shift();}
  get length(){return this.items.length;}
}

import {describe,it} from 'vitest';
import fc from 'fast-check';
import {Queue} from './queue';

describe('Queue FIFO',()=>{
  it('preserves order',()=>{
    fc.assert(fc.property(fc.array(fc.integer()),(items)=>{
      const q=new Queue<number>();
      items.forEach(i=>q.enqueue(i));
      const out:number[]=[];
      while(q.length)out.push(q.dequeue()!);
      return JSON.stringify(out)===JSON.stringify(items);
    }),{numRuns:300});
  });
});

