import {AsyncLocalStorage} from 'node:async_hooks';
export const requestStore=new AsyncLocalStorage<{correlationId:string}>();

import type {RequestHandler} from 'express';
import {randomUUID} from 'node:crypto';
export const correlationMiddleware:RequestHandler=(req,_res,next)=>{
  const id=req.header('x-correlation-id')??randomUUID();
  requestStore.run({correlationId:id},next);
};

export function log(message:string,extra?:Record<string,unknown>){
  const ctx=requestStore.getStore();
  console.log(JSON.stringify({message,correlationId:ctx?.correlationId,...extra}));
}

import {describe,it,expect,vi} from 'vitest';
import express from 'express';
import request from 'supertest';
import {correlationMiddleware,log} from './correlation';

describe('correlation ID',()=>{
  it('propagates through async boundaries',async()=>{
    const logs:string[]=[];
    vi.spyOn(console,'log').mockImplementation((m:string)=>{logs.push(m);});
    const app=express();
    app.use(correlationMiddleware);
    app.get('/',async(_,res)=>{await new Promise(r=>setTimeout(r,5));log('handled');res.json({ok:true});});
    await request(app).get('/').set('x-correlation-id','test-123').expect(200);
    const parsed=JSON.parse(logs.find(l=>l.includes('handled'))!);
    expect(parsed.correlationId).toBe('test-123');
  });
});

