export function isUsPhone(s:string):boolean{return /^\+1[2-9]\d{2}[2-9]\d{6}$/.test(s);}

import {describe,it,expect} from 'vitest';
import fc from 'fast-check';
import {isUsPhone} from './phone';

describe('isUsPhone',()=>{
  it('accepts well-formed +1NXXNXXXXXX',()=>{
    fc.assert(fc.property(fc.integer({min:2,max:9}),fc.integer({min:0,max:999}),fc.integer({min:2,max:9}),fc.integer({min:0,max:999999}),(a,b,c,d)=>{
      const phone=`+1${a}${String(b).padStart(3,'0').slice(0,2)}${c}${String(d).padStart(6,'0').slice(0,6)}`;
      // construction may not always be valid; spot-check the constructor
      const candidate=`+1${a}${String(b).padStart(3,'0').slice(0,2)}${c}${String(d).padStart(6,'0').slice(0,6)}`;
      if(candidate.length===12)return isUsPhone(candidate);
      return true;
    }),{numRuns:200});
  });
  it('rejects short strings',()=>{
    fc.assert(fc.property(fc.string({maxLength:8}),(s)=>!isUsPhone(s)),{numRuns:200});
  });
  it('rejects non-digit content',()=>{
    expect(isUsPhone('+1abc1234567')).toBe(false);
    expect(isUsPhone('phone')).toBe(false);
  });
});

