import {Suspense,use} from 'react';
function Inner({p}:{p:Promise<string>}){const v=use(p);return <span>{v}</span>;}
function Outer({outer,inner}:{outer:string;inner:Promise<string>}){
  return (
    <div>
      <h1>{outer}</h1>
      <Suspense fallback={<div role="status">inner loading</div>}>
        <Inner p={inner}/>
      </Suspense>
    </div>
  );
}
export function Page({outer,inner}:{outer:string;inner:Promise<string>}){
  return (
    <Suspense fallback={<div role="status">outer loading</div>}>
      <Outer outer={outer} inner={inner}/>
    </Suspense>
  );
}

